const now = new Date();
const today = now.toISOString().slice(0, 10);
const due = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
const runId = `N8N-STOCK-BUY-LOCK-${Date.now()}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, dueDate: due, supplierName: `${runId} NCC linked PR`, itemGroup: `${runId} Nhóm mua`, warehouseName: `${runId} Buying Receipt WH`, itemCode: `${runId} Hàng mua tăng tồn`, qty: 3, rate: 72, accounts: { payable: '2110 - Creditors - TDD', expense: '5111 - Cost of Goods Sold - TDD' } } }];

const ctx = $node['Build Buying Stock Lock Context'].json;
const pr = $node['Get Buying Purchase Receipt'].json;
const row = pr.items[0];
return [{ json: { payload: { supplier: $node['Create Buying Lock Supplier'].json.name, company: ctx.company, posting_date: ctx.postingDate, due_date: ctx.dueDate, credit_to: ctx.accounts.payable, remarks: `${ctx.runId} purchase invoice linked to purchase receipt`, items: [{ item_code: row.item_code, qty: row.qty, rate: row.rate, expense_account: ctx.accounts.expense, purchase_receipt: pr.name, pr_detail: row.name }] } } }];

const ctx = $node['Build Buying Stock Lock Context'].json;
const binRows = $('Verify Buying Bin After Receipt').all().map(i => i.json);
const sleRows = $('Verify Buying SLE After Receipt').all().map(i => i.json);
const cancelRows = $('Try Cancel Invoiced Purchase Receipt').all().map(i => i.json);
const prAfter = $node['Get Purchase Receipt After Cancel Attempt'].json;
const invoice = $node['Submit Linked Purchase Invoice'].json;
const actualQty = Number(binRows[0]?.actual_qty ?? NaN);
const cancelFailed = cancelRows.some(row => row.error || row.message || row.httpCode || row.stack);
const text = JSON.stringify({ binRows, sleRows, invoice: { name: invoice.name, docstatus: invoice.docstatus, grand_total: invoice.grand_total }, cancelRows, prAfter: { name: prAfter.name, docstatus: prAfter.docstatus, per_billed: prAfter.per_billed } });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
const status = actualQty === ctx.qty && sleRows.length >= 1 && Number(invoice.docstatus) === 1 && Number(prAfter.docstatus) === 1 && cancelFailed && securityFindings.length === 0 ? 'passed' : 'failed';
return [{ json: { status, runId: ctx.runId, supplier: $node['Create Buying Lock Supplier'].json.name, item: $node['Create Buying Lock Item'].json.name, warehouse: $node['Create Buying Lock Warehouse'].json.name, purchaseReceipt: $node['Create Buying Purchase Receipt'].json.name, purchaseReceiptDocstatusAfterCancelAttempt: prAfter.docstatus, purchaseReceiptPerBilled: prAfter.per_billed, purchaseInvoice: invoice.name, purchaseInvoiceDocstatus: invoice.docstatus, purchaseInvoiceGrandTotal: invoice.grand_total, binActualQtyAfterReceipt: actualQty, receiptLedgerRows: sleRows.length, receiptLedgerActualQty: sleRows.map(row => row.actual_qty), receiptLedgerQtyAfterTransaction: sleRows.map(row => row.qty_after_transaction), cancelFailedAsExpected: cancelFailed, cancelError: cancelRows.map(row => row.error || row.message || row.httpCode || 'no error captured'), securityFindings } }];
